import React, { useState, useEffect } from 'react';
import './UserHomePage.css';
import api from '../api';
import DocumentUpload from './DocumentUpload';

export default function UserHomePage({ username, onLogout, onDocumentsUploaded }) {
  const [documentStatus, setDocumentStatus] = useState('NOT_UPLOADED');
  const [showDocumentUpload, setShowDocumentUpload] = useState(false);
  const [loading, setLoading] = useState(true);
  const [aiVerificationFile, setAiVerificationFile] = useState(null);
  const [aiVerificationType, setAiVerificationType] = useState('');
  const [aiVerificationLoading, setAiVerificationLoading] = useState(false);
  const [aiVerificationResult, setAiVerificationResult] = useState(null);

  useEffect(() => {
    checkDocumentStatus();
  }, [username]);

  const checkDocumentStatus = async () => {
    try {
      const response = await api.get(`/documents/user/${username}`);
      const documents = response.data;

      if (documents.length === 0) {
        setDocumentStatus('NOT_UPLOADED');
      } else {
        const allVerified = documents.every(doc => doc.uploadStatus === 'VERIFIED');
        const anyPending = documents.some(doc => doc.uploadStatus === 'UPLOADED');

        if (allVerified && documents.length >= 2) {
          setDocumentStatus('VERIFIED');
          onDocumentsUploaded();
        } else if (anyPending) {
          setDocumentStatus('PENDING');
        } else {
          setDocumentStatus('NOT_UPLOADED');
        }
      }
    } catch (error) {
      console.error('Error checking document status:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDocumentUpload = () => {
    setShowDocumentUpload(true);
  };

  const handleBackToHome = () => {
    setShowDocumentUpload(false);
    checkDocumentStatus();
  };

  const handleAiVerification = async () => {
    if (!aiVerificationFile || !aiVerificationType) {
      alert('Please select a file and document type');
      return;
    }

    setAiVerificationLoading(true);
    setAiVerificationResult(null);

    try {
      // Create FormData for file upload
      const formData = new FormData();
      formData.append('file', aiVerificationFile);
      formData.append('document_type', aiVerificationType);

      // Upload document to auto-kyc backend
      const uploadResponse = await api.post('http://localhost:8000/upload-document', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });

      if (uploadResponse.data.success) {
        // Analyze the uploaded document
        const analyzeResponse = await api.post('http://localhost:8000/api/analyze-document', {
          file_path: uploadResponse.data.file_path,
        });

        if (analyzeResponse.data.success) {
          const verificationData = analyzeResponse.data.data;

          // Update document status in Java backend
          await api.post(`/documents/verify-by-ai/${username}`, {
            documentType: aiVerificationType,
            verificationData: verificationData,
            status: 'VERIFIED',
            comments: 'Automatically verified by AI system'
          });

          setAiVerificationResult({
            success: true,
            data: verificationData,
            message: 'Document verified successfully by AI!'
          });

          // Refresh document status
          setTimeout(() => {
            checkDocumentStatus();
            setAiVerificationResult(null);
          }, 3000);
        }
      }
    } catch (error) {
      console.error('AI Verification error:', error);
      setAiVerificationResult({
        success: false,
        message: 'AI verification failed. Please try again.'
      });
    } finally {
      setAiVerificationLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="user-homepage">
        <div className="loading-container">
          <div className="spinner"></div>
          <p>Loading your dashboard...</p>
        </div>
      </div>
    );
  }

  if (showDocumentUpload) {
    return (
      <div className="document-upload-page">
        <div className="upload-header">
          <button onClick={handleBackToHome} className="back-btn">
            ← Back to Dashboard
          </button>
          <h1>📋 Upload Your Documents</h1>
          <p>Please upload your Aadhaar Card and PAN Card for verification</p>
        </div>
        <DocumentUpload username={username} />
      </div>
    );
  }

  return (
    <div className="user-homepage">
      {/* Header */}
      <div className="homepage-header">
        <div className="header-content">
          <h1>🏦 Welcome to Secure Bank</h1>
          <p>Hello, <strong>{username}</strong>! Complete your document verification to access banking services.</p>
        </div>
        <button onClick={onLogout} className="logout-btn">
          Logout
        </button>
      </div>

      {/* Action Buttons */}
      <div className="action-section">
        {documentStatus === 'NOT_UPLOADED' && (
          <div className="action-buttons">
            <button onClick={handleDocumentUpload} className="action-btn primary">
              📤 Upload Documents
            </button>
          </div>
        )}

        {documentStatus === 'PENDING' && (
          <div className="pending-message">
            <div className="pending-icon">⏳</div>
            <h3>Verification in Progress</h3>
            <p>Your documents are being reviewed. This usually takes 1-2 business days.</p>
          </div>
        )}

        {documentStatus === 'VERIFIED' && (
          <div className="success-message">
            <div className="success-icon">✅</div>
            <h3>All Set!</h3>
            <p>Your account is fully verified. You can now access all banking services.</p>
            <button className="action-btn success" onClick={onDocumentsUploaded}>
              Go to Dashboard
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
